module TopModule (input logic clk, input logic reset, output logic [3:0] q); localparam STATE_0 = 4'd0; localparam STATE_1 = 4'd1; localparam STATE_2 = 4'd2; localparam STATE_3 = 4'd3; localparam STATE_4 = 4'd4; localparam STATE_5 = 4'd5; localparam STATE_6 = 4'd6; localparam STATE_7 = 4'd7; localparam STATE_8 = 4'd8; localparam STATE_9 = 4'd9; logic [3:0] state; initial begin state = STATE_0; end always @(posedge clk) begin if (reset) state <= STATE_0; else case (state) STATE_0: state <= STATE_1; STATE_1: state <= STATE_2; STATE_2: state <= STATE_3; STATE_3: state <= STATE_4; STATE_4: state <= STATE_5; STATE_5: state <= STATE_6; STATE_6: state <= STATE_7; STATE_7: state <= STATE_8; STATE_8: state <= STATE_9; STATE_9: state <= STATE_0; endcase end assign q = state; endmodule